import { useState, useRef, useEffect } from 'react';

const navLinks = [
  { href: '/', label: 'Accueil' },
  { href: '/catalogue', label: 'Catalogue' },
  { href: '/promotions', label: 'Promos' },
  { href: '/contact', label: 'Contact' }
];

function ResponsiveMenu() {
  const [isOpen, setIsOpen] = useState(false);
  const menuRef = useRef(null);

  const toggleMenu = () => setIsOpen(!isOpen);
  const closeMenu = () => setIsOpen(false);

  // Fermer avec Escape
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'Escape' && isOpen) closeMenu();
    };
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [isOpen]);

  // Fermer si clic à l'extérieur
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (menuRef.current && !menuRef.current.contains(e.target) && isOpen) closeMenu();
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isOpen]);

  return (
    <nav ref={menuRef} className="relative">
      {/* Bouton hamburger mobile */}
      <button
        className="block md:hidden p-2 focus:outline-none focus:ring-2 focus:ring-indigo-500 rounded"
        onClick={toggleMenu}
        aria-expanded={isOpen}
        aria-label="Menu"
      >
        <span className="text-2xl">{isOpen ? '✕' : '☰'}</span>
      </button>

      {/* Menu desktop */}
      <div className="hidden md:flex gap-6">
        {navLinks.map(link => (
          <a key={link.href} href={link.href} className="hover:text-indigo-600">
            {link.label}
          </a>
        ))}
      </div>

      {/* Menu mobile overlay */}
      {isOpen && (
        <div className="absolute top-full left-0 w-full bg-white shadow-lg md:hidden z-20">
          {navLinks.map(link => (
            <a
              key={link.href}
              href={link.href}
              onClick={closeMenu}
              className="block p-4 border-b hover:bg-gray-50 focus:bg-gray-100"
            >
              {link.label}
            </a>
          ))}
        </div>
      )}
    </nav>
  );
}

export default ResponsiveMenu;
```
